# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor.Actor

class AccountManager extends Actor {
  private var balance = 0

  def receive = {
    case Deposit(amount) =>
      balance += amount
      sender() ! s"Deposited $amount, new balance is $balance"

    case Withdrawal(amount) =>
      if (balance >= amount) {
        balance -= amount
        sender() ! s"Withdrew $amount, new balance is $balance"
      } else {
        sender() ! "Insufficient funds"
      }

    case GetBalance =>
      sender() ! s"Current balance is $balance"

    case _ => sender() ! "Unknown message"
  }
}

case class Deposit(amount: Int)
case class Withdrawal(amount: Int)
case object GetBalance